type Item = {
    nom: string;
    prixUnitaire: number;
};

type Panier = {
    items: Item[];
    taxe: number;
};

type ErreurPanier = 
    | { type: 'PANIER_VIDE'; message: string }
    | { type: 'ITEM_SANS_PRIX'; message: string }
    | { type: 'TAXE_NEGATIVE'; message: string };

function calculerMontantTTC(panier: Panier): number | ErreurPanier {
    if (panier.items.length === 0) {
        return { type: 'PANIER_VIDE', message: 'Le panier est vide.' };
    }

    if (panier.taxe < 0) {
        return { type: 'TAXE_NEGATIVE', message: 'La taxe ne peut pas être négative.' };
    }

    for (const item of panier.items) {
        if (typeof item.prixUnitaire !== 'number' || item.prixUnitaire < 0) {
            return { type: 'ITEM_SANS_PRIX', message: `L'item "${item.nom}" n'a pas de prix valide.` };
        }
    }

    const montantTTC = panier.items.reduce((accumulateur, item) => {
        return accumulateur + item.prixUnitaire * panier.taxe;
    }, 0);

    return montantTTC;
}
